/**
 * A container that groups multiple `Item` components into a vertical list layout.
 *
 * Renders as `<ul role="list">` so grouped items are announced as a list.
 *
 * ### Component Props
 *
 * Accepts all standard `<ul>` HTML element props.
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <ItemGroup>
 *   <Item>
 *     <ItemContent>
 *       <ItemTitle>First item</ItemTitle>
 *     </ItemContent>
 *   </Item>
 *   <ItemSeparator />
 *   <Item>
 *     <ItemContent>
 *       <ItemTitle>Second item</ItemTitle>
 *     </ItemContent>
 *   </Item>
 * </ItemGroup>
 * ```
 */
declare function ItemGroup({ className, ...props }: React.ComponentProps<'ul'>): react_jsx_runtime.JSX.Element;
/**
 * A horizontal separator for visually dividing items within an `ItemGroup`.
 *
 * Renders as an `<li aria-hidden="true">` so it is a valid child of
 * `ItemGroup`'s `<ul>` (satisfying HTML's content model and WCAG 1.3.1)
 * while being hidden from assistive technologies as a purely decorative
 * divider.
 *
 * ### Component Props
 *
 * Accepts all standard `<li>` HTML element props.
 *
 *
 * ### Example Usage
 *
 * ```tsx
 * <ItemGroup>
 *   <Item>...</Item>
 *   <ItemSeparator />
 *   <Item>...</Item>
 * </ItemGroup>
 * ```
 */
declare function ItemSeparator({ className, ...props }: React.ComponentProps<'li'>): react_jsx_runtime.JSX.Element;
declare const itemVariants: (props?: ({
    variant?: "default" | "outline" | "muted" | null | undefined;
    size?: "default" | "xs" | "sm" | null | undefined;
} & class_variance_authority_types.ClassProp) | undefined) => string;
/**
 * A versatile list item component with variant and size options for displaying structured content.
 *
 * Renders as `<li>` by default so it composes cleanly inside `ItemGroup`'s
 * `<ul>` container without violating list semantics. When used standalone
 * (outside an `ItemGroup`), use `asChild` to render as a different element.
 *
 * ### Component Props
 *
 * Accepts all standard `<li>` HTML element props, plus:
 *
 * | Prop      | Type                                | Default     |
 * | :-------- | :---------------------------------- | :---------- |
 * | _variant_ | `"default" \| "outline" \| "muted"` | `"default"` |
 * | _size_    | `"default" \| "sm" \| "xs"`         | `"default"` |
 * | _asChild_ | `boolean`                           | `false`     |
 *
 *
 * ### Example Usage
 *
 * **Default**
 * ```tsx
 * <Item>
 *   <ItemContent>
 *     <ItemTitle>Default item</ItemTitle>
 *     <ItemDescription>No border, standard padding</ItemDescription>
 *   </ItemContent>
 * </Item>
 * ```
 *
 * **Outline + Small**
 * ```tsx
 * <Item variant="outline" size="sm">
 *   <ItemMedia variant="icon">
 *     <FileIcon />
 *   </ItemMedia>
 *   <ItemContent>
 *     <ItemTitle>Document</ItemTitle>
 *     <ItemDescription>A brief description</ItemDescription>
 *   </ItemContent>
 * </Item>
 * ```
 *
 * **Muted + Extra Small**
 * ```tsx
 * <Item variant="muted" size="xs">
 *   <ItemContent>
 *     <ItemTitle>Compact muted item</ItemTitle>
 *   </ItemContent>
 * </Item>
 * ```
 */
declare function Item({ className, variant, size, asChild, ...props }: React.ComponentProps<'li'> & VariantProps<typeof itemVariants> & AsChild): react_jsx_runtime.JSX.Element;
declare const itemMediaVariants: (props?: ({
    variant?: "image" | "icon" | "default" | null | undefined;
} & class_variance_authority_types.ClassProp) | undefined) => string;
